INSERT INTO `v1_97bad1c439e41378af96b42f6c469a9856b9e2e5958297031db976ade1834b71` VALUES ("イベントボスには非常に高い「Total HP」が設定されております。\n「Total HP」は、皆さまがバトル中に与えたダメージの分だけ減らせる\nのだとか。豪華報酬を目指し、力を合わせて討伐いたしましょう。", 2, 1012, 1, 1);
INSERT INTO `v1_97bad1c439e41378af96b42f6c469a9856b9e2e5958297031db976ade1834b71` VALUES ("ボスバトルは、イベント期間中に配布される「討伐チケット」を消費して\n挑戦できます。また、難易度は「ボス詳細」から変更できますよ。\n討伐を達成した難易度はスキップも行えるので、活用してくださいまし。", 3, 1013, 1, 1);
INSERT INTO `v1_97bad1c439e41378af96b42f6c469a9856b9e2e5958297031db976ade1834b71` VALUES ("報酬交換では「討伐報酬券」と様々なアイテムを交換できます。\n目玉となるリセット対象報酬を引くことで、より多くのアイテムが\n獲得できる次のラインナップへと進めるそうです。", 4, 1021, 2, 1);
